cache = redis.Redis(host='localhost', port=6379)

def cache_result(timeout: int):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            # Define a custom key based on function name and its arguments
            key = f"{func.__name__}_{str(hash(str(args) + str(kwargs)))}"
            result = cache.get(key)
            if not result:
                result = func(*args, **kwargs)
                cache.setex(key, timeout, result)  # Set value with a TTL (time-to-live) of `timeout` seconds
            return result
        return wrapper
    return decorator

